import React, { useState, useContext } from 'react';
import { useLocation } from 'react-router-dom';
import { EastereggContext } from '../context/EastereggContext';

import coinBlock from '../../static/img/block.png';
import easterMush from '../../static/img/shroom.gif';
import easterStar from '../../static/img/star.gif';
import easterPlant from '../../static/img/plant.gif';
import coinMp3 from '../../static/sound/coin.mp3';
import levelUpMp3 from '../../static/sound/levelup.mp3';

import MusicPlayer from './MusicPlayer';

function Nav() {
    const [coinCount, setCoinCount] = useState(0);
    const [currentSong, setCurrentSong] = useState({"key": null, "state": null});
    const [eastereggState, setEastereggState] = useContext(EastereggContext);
    let location = useLocation();

    function onlyVisibleOnIndex() {
        if (location.pathname.length > 1) return " hidden";
        else return "";
    }

    function incrementCoin() {
        let coinSound = new Audio(coinMp3);
        coinSound.volume = 0.2;
        coinSound.play();
        setCoinCount(coinCount+1);
    }

    function buyEasteregg() {
        let isAlreadyUnlocked = eastereggState.darkMode.unlocked;
        if (coinCount < 10 || isAlreadyUnlocked) return;
        setCoinCount(coinCount-10);
        unlockEasteregg("darkMode");
    }

    function unlockEasteregg(part) {
        let isAlreadyUnlocked = eastereggState[part].unlocked;
        if (isAlreadyUnlocked) return;
        let levelUpSound = new Audio(levelUpMp3);
        levelUpSound.volume = 0.2;
        levelUpSound.play();
        setEastereggState(prevState => ({
            ...prevState,
            [part]: {
                ...prevState[part],
                "unlocked": true
            }
        }));
    }

    function toggleEasteregg(part) {
        let currentUnlockedStatus = eastereggState[part]["unlocked"];
        if (!currentUnlockedStatus) return;
        let currentActiveStatus = eastereggState[part]["active"];
        setEastereggState(prevState => ({
            ...prevState,
            [part]: {
                ...prevState[part],
                "active": !currentActiveStatus
            }
        }));

        if (part === "musicPlay") toggleMusic(currentActiveStatus);
    }

    function toggleMusic(isPlaying) {
        if (!isPlaying) {
            let randomNumber = Math.floor(Math.random() * 7);
            if (!currentSong.key) setCurrentSong({"key": randomNumber, "state": "PLAYING"});
            else setCurrentSong({...currentSong, "state": "PLAYING"});
        } else {
            setCurrentSong({...currentSong, "state": "PAUSED"});
        }
    }

    function nextSong() {
        let randomNumber = Math.floor(Math.random() * 7);
        setCurrentSong({"key": randomNumber, "state": "PLAYING"});
    }

    return (
        <>
            <div className="easteregg-container">
                <img className={`coinblock${onlyVisibleOnIndex()}`} src={coinBlock} alt="" onClick={() => incrementCoin()}></img>
                <div className="coincount">
                    {!onlyVisibleOnIndex() ? <><p>{coinCount} <i className="fas fa-coins"></i></p></> : ""}
                </div>
                <div className="coinshop">
                    {!onlyVisibleOnIndex() ? 
                        <>
                            <p onClick={() => buyEasteregg()}>
                                {!eastereggState.darkMode.unlocked ? (
                                    <>
                                        <i className="fas fa-key"></i> &nbsp;
                                        <i className="fas fa-long-arrow-alt-right"></i>&nbsp; 10 &nbsp;
                                        <i className="fas fa-coins"></i>
                                    </>
                                ) : (
                                    <>
                                        <i className="fas fa-check"></i>
                                    </>
                                )}
                            </p>
                        </>
                    : null}
                </div>
                <div className="lilcollection">
                    <div data-tooltip="Buy it!" onClick={() => toggleEasteregg("darkMode")}>
                        {
                            eastereggState.darkMode.unlocked ? 
                            <img src={easterMush} alt="easteregg-mush"></img> 
                            : <i className="fas fa-key"></i>
                        }
                    </div>
                    <div data-tooltip="Where am I?" onClick={() => toggleEasteregg("musicPlay")}>
                        {
                            eastereggState.musicPlay.unlocked ? 
                            <img src={easterStar} alt="easteregg-star"></img>
                            : <i className="fas fa-key"></i>
                         }
                    </div>
                    <div data-tooltip="Contact me!" onClick={() => toggleEasteregg("revealSecret")}>
                        {
                            eastereggState.revealSecret.unlocked ? 
                            <img src={easterPlant} alt="easteregg-plant"></img>
                            : <i className="fas fa-key"></i>
                         }
                    </div>
                </div>
                <MusicPlayer currentSong={currentSong} nextSong={nextSong} />
            </div>
        </>
    );
}

export default Nav;