import React from 'react';

function Picture(props) {
    return (
        <div className="csdescriptionlist-img">
            <div className="cvimg" onClick={() => props.clickEvent("musicPlay")}>
                <img src={props.source} alt=""></img>
                <i className={
                    props.iconState ? "fas fa-check" : "fas fa-key"
                }></i>
            </div>
        </div>
    );
}

export default Picture;