import React from 'react';

function ContactBar(props) {
    return (
        <>
        {props.media.special ? 
            <div onClick={() => props.clickEvent("revealSecret")} className="contactpart special">
                <i style={{backgroundColor: props.media.color}} className={props.unlocked ? "fas fa-check" : props.media.icon}></i>
                <p>{props.media.label}</p>
            </div>
        :
            <a href={props.media.href} target="_blank" rel="noreferrer">
                <div className="contactpart">
                    <i style={{backgroundColor: props.media.color}} className={props.media.icon}></i>
                    <p>{props.media.label}</p>
                </div>
            </a>
        }
        </>
    );
}

export default ContactBar;