import React, { useState } from 'react';
import HobbyBtn from './about/HobbyBtn';

import aboutData from '../../data/about.json';

function About() {
    const [selectedHobby, setSelectedHobby] = useState({
        "key": "",
        "icon": "",
        "decription": "Click on one of the icons if you want to know more about me!",
        "backgroundColor": ""
    });

    function updateSelectedHobby(val) {
        if (val === selectedHobby.key) return;
        let hobby = aboutData.hobbies[val];
        setSelectedHobby({
            "key": val,
            "icon": <i className={hobby.icon}></i>,
            "description": hobby.info,
            "backgroundColor": hobby.color
        });
    }

    return (
        <div className="curr_tab_aboutme">
            <h2>Short Story</h2>
                <div className="cvdescription">
                    <p>
                        {aboutData.description.part1}
                    </p>
                    <p>
                        {aboutData.description.part2}
                    </p>
                </div>
                <h2>Hobbies</h2>
                <div>
                    <div className="hobbyiconwrap">
                        {aboutData.hobbies.map((hobby, index) => {
                            return <HobbyBtn hobby={hobby} key={index} clickEvent={updateSelectedHobby} value={index} />
                        })}
                    </div>
                    <div className="hobbytextcont">
                        <div style={selectedHobby.backgroundColor ? {backgroundColor: selectedHobby.backgroundColor} : null} className="hobbytexticon">{selectedHobby.icon}</div>
                        <div className="hobbytextinfo">
                            <p>{selectedHobby.description}</p>
                        </div>
                    </div>
                </div>
        </div>
    );
}

export default About;