import React, { useState, createContext } from 'react';

export const EastereggContext = createContext();

export const EastereggProvider = (props) => {
    const [eastereggState, setEastereggState] = useState({
        darkMode: {"unlocked": false, "active": false},
        musicPlay: {"unlocked": false, "active": false},
        revealSecret: {"unlocked": false, "active": false}
    });

    return (
        <EastereggContext.Provider value={[eastereggState, setEastereggState]}>
            {props.children}
        </EastereggContext.Provider>
    );
};