import React from 'react';
import curriFile from '../../../static/file/myCV.pdf';

function Info(props) {
    return (
        <>
            {props.info.label === "Download" ? (
                <li>
                    <i className={props.info.icon}></i>&nbsp; 
                    <b>{props.info.label}</b>:&nbsp; 
                    <p><a href={curriFile} download="CV - Sebastien Bacs">PDF CV</a></p>
                </li>
            ) : (
                <li>
                    <i className={props.info.icon}></i>&nbsp; 
                    <b>{props.info.label}</b>:&nbsp; 
                    <p dangerouslySetInnerHTML={{__html: props.info.value}}></p>
                </li>
            )}
        </>
    );
}

export default Info;