import React, { useState } from 'react';
import {SRLWrapper} from "simple-react-lightbox";
import portfolioData from '../../data/portfolio.json';

import Slider from './portfolio/Slider';
import Image from './portfolio/Image';
import Accordion from './portfolio/Accordion';


function Portfolio() {
    const options = {
        buttons: {
          backgroundColor: "#555",
          iconColor: "#eee",
          showDownloadButton: false
        },
        settings: {
            slideTransitionSpeed: 0.1,
            lightboxTransitionSpeed: 0.2,
            overlayColor: "rgba(0, 0, 0, 0.95)"
        },
        thumbnails: {
            showThumbnails: false
        }
    };
    
    const [opened, setOpened] = useState(false);
    const toggle = index => {
        if (opened === index) {
            return setOpened(null);
        }
    
        setOpened(index);
    };

    let imagesLibrary = require.context('../../static/img/portfolio', true);

    function importAllImages() {
        let result = [];

        for (let i = 0; i < portfolioData.length; i++) {
            let importedImagesBlock = [];
            for (let j = 0; j < portfolioData[i].images.length; j++) {
                importedImagesBlock.push(<Image source={imagesLibrary(`./${portfolioData[i].images[j]}`).default} key={i} />);
            }
            result.push(importedImagesBlock);
        }

        return result;
    }

    function getSlider(images) {
        return <Slider images={images} />;
    }

    let importedImages = importAllImages();
    
    return (
        <div className="curr_tab_portfolio">
            <SRLWrapper options={options}>
                {portfolioData.map((portfolioDataBlock, index) => {
                    return <Accordion opened={opened} key={index} index={index} toggle={toggle} content={getSlider(importedImages[index])} title={portfolioDataBlock.title}/>
                })}
            </SRLWrapper>
        </div>
    );
}

export default Portfolio;