import React, { useState, useContext } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { EastereggContext } from '../context/EastereggContext';

import logo from '../../static/img/logoseb.png';
import piranhaPlant from '../../static/img/piran.png';

function Nav() {
    const [eastereggState] = useContext(EastereggContext);
    const [toggle, setToggle] = useState(false);
    const [hamburgerClass, setHamburgerClass] = useState(false);
    const [navDisplay, setNavDisplay] = useState("initial");
    const [navPosLeft, setNavPosLeft] = useState(handleNavWidth());
    window.addEventListener('resize', handleResize);

    let location = useLocation();

    function setActiveLink(target) {
        if (location.pathname.indexOf(target) > -1) return "active";
        else return "";
    }

    function toggleNav() {
        if (toggle) {
            setToggle(false);
            setHamburgerClass("");
            setNavPosLeft("-100vw");
        } else {
            setToggle(true);
            setHamburgerClass("is-active");
            setNavPosLeft(0);
        }
    }

    function handleNavWidth() {
        if (window.innerWidth > 960) {
            return 0;
        } else {
            return "-100vw";
        }
    }

    function handleResize() {
        setNavPosLeft(handleNavWidth());
        if (window.innerWidth > 960) {
            setToggle(false);
            setHamburgerClass("");
            setNavDisplay("initial");
        } else {
            setNavDisplay("none");
            setTimeout(() => {
                setNavDisplay("initial");
            }, 500);
        }
    }

    return (
        <>
            <div className="mobiletopbar"></div>
            <div onClick={() => toggleNav()} className={`hamburger hamburger--collapse ${hamburgerClass}`}>
                <div className="hamburger-box">
                    <div className="hamburger-inner"></div>
                </div>
            </div>
            <div style={{left: navPosLeft, display: navDisplay}} className="nav">
                <ul>
                    <Link to="/"><img src={logo} className="logo" alt=""></img></Link>
                    <div className="hr-circle"></div>
                    <Link to="/curriculum"><li className={`buttonsb buttonsbnormal ${setActiveLink("curriculum")}`}><i className="fas fa-user-tie"></i>Curriculum</li></Link>
                    {eastereggState.revealSecret.active ? 
                        <Link to="/secret"><li className={`buttonsb buttonsbnormal ${setActiveLink("secret")}`}><i className="fas fa-key"></i>Secret</li></Link>
                    : null}
                    <div className="hr-circle"></div>
                    <img style={eastereggState.revealSecret.active ? {display: "block"} : {display: "none"}} src={piranhaPlant} className="piranhaplant" alt=""></img>
                </ul >
            </div>
        </>
    );
}

export default Nav;