import React, { useContext } from 'react';
import headerData from '../../data/header.json';
import { EastereggContext } from '../context/EastereggContext';

import Info from './header/Info';
import Picture from './header/Picture';
import levelUpMp3 from '../../static/sound/levelup.mp3';

function Header() {
    const [eastereggState, setEastereggState] = useContext(EastereggContext);
    let imagesLibrary = require.context('../../static/img', true);
    let image = imagesLibrary(`./${headerData.image}`);
    let profileInfo = mapProfInfo();

    function mapProfInfo() {
        let half = Math.ceil(headerData.info.length / 2);
        let result = [];

        result.push(headerData.info.slice(0, half));
        result.push(headerData.info.slice(half, headerData.info.length));

        return result;
    }

    function createSkillBlocks(profInfo, index) {
        let currentProfileInfo = profInfo[index];
        return (
            <div className="csdescriptionlist-block" key={index}>
                {currentProfileInfo.map((info, index) => {
                    return <Info info={info} key={index}/>
                })}
            </div>
        );
    }

    function unlockEasteregg(part) {
        let isAlreadyUnlocked = eastereggState[part].unlocked;
        if (isAlreadyUnlocked) return;
        let levelUpSound = new Audio(levelUpMp3);
        levelUpSound.volume = 0.2;
        levelUpSound.play();
        setEastereggState(prevState => ({
            ...prevState,
            [part]: {
                ...prevState[part],
                "unlocked": true
            }
        }));
    }

    return (
        <>
            <h1 className="h1-hr">Curriculum</h1>
            <Picture source={image.default} clickEvent={unlockEasteregg} iconState={eastereggState.musicPlay.unlocked} />
            <ul className="csdescriptionlist">
                {createSkillBlocks(profileInfo, 0)}
                <Picture source={image.default} clickEvent={unlockEasteregg} iconState={eastereggState.musicPlay.unlocked} />
                {createSkillBlocks(profileInfo, 1)}
            </ul>
        </>
    );
}

export default Header;