import React from 'react';
import Bar from './skill/Bar';

import skillData from '../../data/skill.json';

function Skill() {
    let progSkillsBlocks = mapProgSkills();

    function mapProgSkills() {
        let half = Math.ceil(skillData.programming.length / 2);
        let result = [];

        result.push(skillData.programming.slice(0, half));
        result.push(skillData.programming.slice(half, skillData.programming.length));

        return result;
    }

    function createSkillBlocks(progSkills, index) {
        return (
            <div key={index}>
                {progSkills.map((skill, index) => {
                    return <Bar skill={skill} key={index} />
                })}
            </div>
        );
    }

    return (
        <div className="curr_tab_skills">
            <h2>Language</h2>
            <div className="languagebars">
                {skillData.language.map((skill, index) => {
                    return <Bar skill={skill} key={index} />
                })}
            </div>
            <h2>Programming</h2>
            <div className="skillbars">
                {progSkillsBlocks.map((skillBlock, index) => {
                    return createSkillBlocks(skillBlock, index);
                })}
            </div>
        </div>
    );
}

export default Skill;