import React from 'react';

function Accordion(props) {
    return (
        <div className="accordion">
            <div onClick={() => props.toggle(props.index)} key={props.index} className="accordion-wrap">
                <h2>{props.title}</h2>
                <i className={props.opened === props.index ? "fas fa-minus" : "fas fa-plus"}></i>
            </div>
            <div style={props.opened === props.index ? {height: "300px"} : {height: "0px"}} className="accordion-dropdown">
                {props.content}
            </div>
        </div>
    );
}

export default Accordion;