import React from 'react';
import AliceCarousel from 'react-alice-carousel';

function Slider(props) {
    const responsive = {
        0: { items: 1 },
        500: { items: 2 },
        640: { items: 3 },
        980: { items: 4 },
        1200: { items: 5 },
    };

    return (
        <AliceCarousel 
            mouseTracking
            responsive={responsive}
            controlsStrategy="alternate" 
            items={props.images} 
            touchTracking={false}
            touchMoveDefaultEvents={false}
            swipeDelta={5000}
        />
    );
}

export default Slider;