import React from 'react';
import { Link, useRouteMatch, useLocation } from 'react-router-dom';

function Subnav() {

    let {url} = useRouteMatch();
    let location = useLocation();

    function isActive(path) {
        if (location.pathname.indexOf(path) > -1) return "active";
        else if (path === "skills" && location.pathname.length === 11) return "active";
    }

    return (
        <div className="curriculum-sub-nav">
            <ul>
                <Link to={`${url}/skills`} className={isActive("skills")}><li></li></Link>
                <Link to={`${url}/experiences`} className={isActive("experiences")}><li></li></Link>
                <Link to={`${url}/about`} className={isActive("about")}><li></li></Link>
                <Link to={`${url}/portfolio`} className={isActive("portfolio")}><li></li></Link>
                <Link to={`${url}/contact`} className={isActive("contact")}><li></li></Link>
            </ul>
        </div>
    );
}

export default Subnav;