import React from 'react';

function HobbyBtn(props) {
    return (
        <div onClick={() => props.clickEvent(props.value)} className="hobbycontainer">
            <div style={{background: props.hobby.color}} className="hobbyicon"><i className={props.hobby.icon}></i></div>
            <p>{props.hobby.name}</p>
        </div>
    );
}

export default HobbyBtn;