import React, {useState} from 'react';

function ExperienceInfo(props) {
    const [toggle, setToggle] = useState(false);
    const [cssOpacity, setCssOpacity] = useState(0);
    const [cssDisplay, setCssDisplay] = useState("none");
    const [cssInnerWidth, setCssInnerWidth] = useState("100%");
    const [cssWidth, setCssWidth] = useState("calc(50% - 10rem)");
    const [btnIcon, setBtnIcon] = useState("fas fa-plus");
    const [btnState, setBtnState] = useState(false);

    let imagesLibrary = require.context('../../../static/img', true);
    let image = imagesLibrary(`./${props.experience.image}`);
    let imageCss = `url(${image.default})`;

    function clickPlus() {
        if (toggle) {
            setToggle(false);
            setBtnIcon("fas fa-plus");
            setCssOpacity(0);
            setBtnState(true);
            setTimeout(() => {
                setCssDisplay("none");
                setTimeout(() => {
                    setCssWidth("calc(50% - 10rem)");
                    setCssInnerWidth("100%");
                    setBtnState(false);
                }, 100);
            }, 500);
        } else {
            setToggle(true);
            setCssWidth("calc(100% - 10rem)");
            setCssInnerWidth("calc(("+window.innerWidth+"px - 427px) / 2 - 10rem)");
            setBtnIcon("fas fa-minus");
            setBtnState(true);
            setTimeout(() => {
                setCssDisplay("inline-block");
                setTimeout(() => {
                    setCssOpacity(1);
                    setBtnState(false);
                }, 100);
            }, 500);
        }
        
    }

    return (
        <div>
            <button onClick={() => clickPlus()} className="timeline-info-plus" disabled={btnState}><i className={btnIcon}></i></button>
            <section style={{width: cssWidth}} className="timeline-info-container">
                <section style={{backgroundImage: imageCss}} className="timeline-info-picture">
                    <a rel="noreferrer" target="_blank" href={props.experience.site} className="currbtn"><i className="fas fa-link"></i></a>
                    <a rel="noreferrer" target="_blank" href={props.experience.location} className="currbtn"><i className="fas fa-map-marker-alt"></i></a>
                </section>
                <section className="timeline-info-header">
                    <section className="title"><i className={props.experience.icon}></i>&nbsp;{props.experience.name}</section>
                    <section className="time">{props.experience.yearDetail}</section>
                </section>
                <section className="timeline-info-content">
                    <section style={{width: cssInnerWidth}} className="timeline-info-skills">
                        <ul>
                            {props.experience.points.map((point, index) => {
                                return <li key={index}>{point}</li>
                            })}
                        </ul>
                    </section>
                    <section dangerouslySetInnerHTML={{__html: props.experience.info}}  style={{display: cssDisplay, opacity: cssOpacity}} className="timeline-info-description">
                    </section>
                </section>
            </section>
        </div>
    );
}

export default ExperienceInfo;