import React, { useState, useContext } from 'react';
import { EastereggContext } from '../context/EastereggContext';
import Sound from 'react-sound';

import song1 from '../../static/sound/song1.mp3';
import song2 from '../../static/sound/song2.mp3';
import song3 from '../../static/sound/song3.mp3';
import song4 from '../../static/sound/song4.mp3';
import song5 from '../../static/sound/song5.mp3';
import song6 from '../../static/sound/song6.mp3';
import song7 from '../../static/sound/song7.mp3';

function MusicPlayer(props) {
    const [easterEggState] = useContext(EastereggContext);
    const [volume, setVolume] = useState(null);
    const [toggleVolumeControll, setToggleVolumeControl] = useState(false);
    const playList = [
        {audio: song1, name: "Broken Wings"},
        {audio: song2, name: "We Are The Champions"},
        {audio: song3, name: "Mandalorian"},
        {audio: song4, name: "Aerodynamic"},
        {audio: song5, name: "Good Thing"},
        {audio: song6, name: "Trampoline"},
        {audio: song7, name: "In This Shirt"}
    ];

    function toggleVolumentControllFunc() {
        setToggleVolumeControl(!toggleVolumeControll)
    }

    return (
        <>
            {playList.map((song, index) => {
                    return <Sound key={index} url={song.audio} onFinishedPlaying={() => props.nextSong()} volume={volume ? volume : 50}
                        playStatus={
                            props.currentSong.key === index ? 
                            props.currentSong.state : "STOPPED"
                        } 
                    />
            })}
            {easterEggState.musicPlay.active ? (
                <>
                    <div className={`easteregg2-extra`+(!toggleVolumeControll ? " hidden" : "")}>
                        <div className="easteregg2volume">
                            <input className="musicvolume" type="range" min="1" max="100" onChange={(e) => {setVolume(parseInt(e.target.value))}}>
                            </input>
                        </div>
                    </div>
                    <div className="easteregg2">
                        <canvas className="musicplayer" id="musicplayer" width="260" height="45"></canvas>
                        <i className="fas fa-volume-down" onClick={() => toggleVolumentControllFunc()}></i>
                        <i className="fas fa-step-forward" onClick={() => props.nextSong()}></i>
                        <p>{playList[props.currentSong.key] ? playList[props.currentSong.key].name : null}</p>
                    </div>
                </>
            ) : null}
        </>
    );
}

export default MusicPlayer;