import React from 'react';

function ExperienceBtn(props) {
    return (
        <div onClick={() => props.clickEvent(props.keyVal)} className={`input ${props.activeString}`}>
            <span data-info={props.experience.name}></span>
            <i className={props.experience.icon}></i>
            <p className="inputlabel">
                {props.experience.year}
            </p>
        </div>
    );
}

export default ExperienceBtn;