import React from 'react';
import { Route, useRouteMatch } from 'react-router-dom';

import Header from '../components/curriculum/Header';
import Subnav from '../components/curriculum/Subnav';
import Skill from '../components/curriculum/Skill';
import Experience from '../components/curriculum/Experience';
import About from '../components/curriculum/About';
import Portfolio from '../components/curriculum/Portfolio';
import Contact from '../components/curriculum/Contact';

function Curriculum() {
    let {path} = useRouteMatch();

    return (
        <>
            <div className="card">
                <Header />
                <Subnav />
                <Route path={`${path}`} component={Skill} exact/>
                <Route path={`${path}/skills`} component={Skill} />
                <Route path={`${path}/experiences`} component={Experience} />
                <Route path={`${path}/about`} component={About} />
                <Route path={`${path}/portfolio`} component={Portfolio} />
                <Route path={`${path}/contact`} component={Contact} />
            </div>
            <div className="clearfix"></div>
        </>
    );
}

export default Curriculum;