import React from 'react';

import video from '../static/video/index.mp4';

function Home() {
    return (
        <div className="index-video-container">
            <div className="sub-vid-container">
                <div className="videokeep">
                    <video className="uk-width-1-1 video" playsInline autoPlay muted>
                        <source src={video} type="video/mp4"></source>
                    </video>
                </div>
            </div>
        </div>
    );
}

export default Home;