import React, { useContext } from 'react';
import Map from './contact/Map';
import ContactBar from './contact/ContactBar';
import { EastereggContext } from '../context/EastereggContext';

import contactData from '../../data/contact.json';
import levelUpMp3 from '../../static/sound/levelup.mp3';

function Contact() {
    const [eastereggState, setEastereggState] = useContext(EastereggContext);

    function unlockEasteregg(part) {
        let isAlreadyUnlocked = eastereggState[part].unlocked;
        if (isAlreadyUnlocked) return;
        let levelUpSound = new Audio(levelUpMp3);
        levelUpSound.volume = 0.2;
        levelUpSound.play();
        setEastereggState(prevState => ({
            ...prevState,
            [part]: {
                ...prevState[part],
                "unlocked": true
            }
        }));
    }

    return (
        <div className="curr_tab_contact">
            <h2>Map</h2>
            <Map map={contactData.map} />
            <h2>Social</h2>
            {contactData.media.map((media, index) => {
                return <ContactBar media={media} key={index} clickEvent={unlockEasteregg} unlocked={eastereggState.revealSecret.unlocked} />
            })}
        </div>
    );
}

export default Contact;