import React, {useState} from 'react';

import experienceData from '../../data/experience.json';
import ExperienceBtn from './experience/ExperienceBtn';
import ExperienceInfo from './experience/ExperienceInfo';

function Experience() {
    const [active, setActive] = useState(0);
    let activeString = "";

    function controlIfActive(key) {
        if (key === active) activeString = "active";
        else activeString = "";
    }

    function updateActive(val) {
        if (val === active) return;
        setActive(val);
    }

    return (
        <div className="curr_tab_experiences">
            <h2>Timeline Experiences</h2>
            <div className="flex-parent">
                <div className="input-flex-container">
                    {experienceData.map((experience, index) => {
                        controlIfActive(index);
                        return <ExperienceBtn experience={experience} key={index} arrayPos={index} activeString={activeString} keyVal={index} clickEvent={updateActive}/>
                    })}
                </div>
                <div className="description-flex-container">
                    <ExperienceInfo experience={experienceData[active]} key={active} />
                </div>
            </div>
        </div>
    );
}

export default Experience;